initial:
# Write Terraform configuration that creates CloudWatch Logs log stream, use awscc provider

# Create CloudWatch Logs Log Group
resource "awscc_logs_log_group" "this" {
  log_group_name    = "SampleLogGroup"
  retention_in_days = 90
  tags = [
    {
      key   = "Name"
      value = "SampleLogGroup"
    },
    {
      key   = "Environment"
      value = "Development"
    },
    {
      key   = "Modified By"
      value = "AWSCC"
    }
  ]
}

# Create CloudWatch Logs Log Stream
resource "awscc_logs_log_stream" "this" {
  log_group_name  = awscc_logs_log_group.this.id
  log_stream_name = "SampleStream"
}

expected:
# Write Terraform configuration that creates CloudWatch Logs log stream, use awscc provider

# Create CloudWatch Logs Log Group
resource "awscc_logs_log_group" "this" {
  log_group_name    = "SampleLogGroup"
  retention_in_days = 90
  tags = [
    {
      key   = "Name"
      value = "SampleLogGroup"
    },
    {
      key   = "Environment"
      value = "Development"
    },
    {
      key   = "Modified By"
      value = "AWSCC"
    }
  ]
}

# Create CloudWatch Logs Log Stream
resource "awscc_logs_log_stream" "this" {
  log_group_name  = awscc_logs_log_group.this.id
  log_stream_name = "SampleStream"
}

# Add a CloudWatch Alarm to monitor the log group
resource "awscc_cloudwatch_alarm" "log_group_alarm" {
  alarm_name               = "SampleLogGroupAlarm"
  comparison_operator      = "GreaterThanOrEqualToThreshold"
  evaluation_periods      = 1
  metric_name              = "IncomingLogEvents"
  namespace                = "AWS/Logs"
  period                   = 300
  statistic                = "Sum"
  threshold                = 10
  alarm_actions            = []
  alarm_description        = "This metric monitors the number of incoming log events to the log group."
  dimensions = {
    LogGroupName = awscc_logs_log_group.this.log_group_name
  }
}

