initial:
# Write Terraform configuration that creates KMS Alias, use awscc provider

# Create KMS Key
resource "awscc_kms_key" "this" {
  key_policy = jsonencode({
    "Version" : "2012-10-17",
    "Id" : "KMS-Key-Policy",
    "Statement" : [
      {
        "Sid" : "Enable IAM User Permissions",
        "Effect" : "Allow",
        "Principal" : {
          "AWS" : "arn:aws:iam::111122223333:root"
        },
        "Action" : "kms:*",
        "Resource" : "*"
      },
    ],
    }
  )
}

# Create KMS Alias
resource "awscc_kms_alias" "this" {
  alias_name    = "alias/example-kms-alias"
  target_key_id = awscc_kms_key.this.key_id
}

expected:
# Write Terraform configuration that creates KMS Alias, use awscc provider

# Create KMS Key
resource "awscc_kms_key" "this" {
  key_policy = jsonencode({
    "Version" : "2012-10-17",
    "Id" : "KMS-Key-Policy",
    "Statement" : [
      {
        "Sid" : "Enable IAM User Permissions",
        "Effect" : "Allow",
        "Principal" : {
          "AWS" : "arn:aws:iam::111122223333:root"
        },
        "Action" : "kms:*",
        "Resource" : "*"
      },
    ],
    }
  )
  description = "KMS Key for example infrastructure"
  key_usage   = "ENCRYPT_DECRYPT"
}

# Create KMS Alias
resource "awscc_kms_alias" "this" {
  alias_name    = "alias/example-kms-alias"
  target_key_id = awscc_kms_key.this.key_id
}

# Create an S3 bucket encrypted with the KMS Key
resource "awscc_s3_bucket" "example_bucket" {
  bucket_name = "example-secure-bucket"
  bucket_encryption {
    server_side_encryption_configuration {
      server_side_encryption_by_default {
        sse_algorithm = "aws:kms"
        kms_master_key_id = awscc_kms_key.this.arn
      }
    }
  }
}

