expected:
# Write Terraform configuration that creates AWS VPC route table with public route to internet gateway, use awscc provider

# Create VPC
resource "awscc_ec2_vpc" "vpc" {
  cidr_block = "10.0.0.0/16"
  tags = [{
    key   = "Managed By"
    value = "AWSCC"
  }]
}

# Create Internet Gateway
resource "aws_internet_gateway" "internet_gateway" {
  vpc_id = awscc_ec2_vpc.vpc.id
}

# Create Public Route Table
resource "aws_route_table" "public_route_table" {
  vpc_id = awscc_ec2_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.internet_gateway.id
  }
}

# Create a new subnet within the VPC
resource "aws_subnet" "public_subnet" {
  vpc_id     = awscc_ec2_vpc.vpc.id
  cidr_block = "10.0.1.0/24"
  tags = {
    Name = "public-subnet"
  }
}

# Associate the public subnet with the public route table
resource "aws_route_table_association" "public_subnet_association" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_route_table.id
}

