expected:
# Write Terraform configuration that creates AWS Amplify Branch, use awscc provider

# Create AWS Amplify App
resource "awscc_amplify_app" "example" {
  name = "app"
}

# Create AWS Amplify Branch within the above AWS Amplify App
resource "awscc_amplify_branch" "main" {
  app_id      = awscc_amplify_app.example.app_id
  branch_name = "main"

  framework = "React"
  stage     = "PRODUCTION"

  environment_variables = [
    {
      name  = "REACT_APP_API_SERVER"
      value = "https://api.example.com"
    },
    {
      name  = "Environment"
      value = "PROD"
    },
  ]
}

# Create an AWS S3 bucket to store build artifacts for the Amplify App
resource "aws_s3_bucket" "amplify_build_artifacts" {
  bucket = "amplify-build-artifacts-${awscc_amplify_app.example.app_id}"
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle_rule {
    id      = "auto-delete-old-versions"
    enabled = true

    noncurrent_version_expiration {
      days = 30
    }
  }

  tags = {
    Name        = "Amplify Build Artifacts"
    AmplifyApp  = awscc_amplify_app.example.name
    Environment = "PROD"
  }
}

