data "aws_kms_key" "by_id" {
  key_id = "alias/aws/rds"
}

# Assume role IAM Policy for RDS enhanced monitoring
data "aws_iam_policy_document" "rds_assume_role_policy" {
  statement {
    actions = ["sts:AssumeRole"]
    effect  = "Allow"
    principals {
      type        = "Service"
      identifiers = ["monitoring.rds.amazonaws.com"]
    }
  }
}

# IAM Role for RDS enhanced monitoring
resource "aws_iam_role" "rds_role" {
  name               = "RDS-Enhanced-Monitoring-Role"
  assume_role_policy = data.aws_iam_policy_document.rds_assume_role_policy.json
  managed_policy_arns = [
    "arn:${data.aws_partition.main.partition}:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
  ]
}

# Create Amazon for RDS SQL Server Standard Edition single az instance with 20 GiB GP3 storage
resource "aws_db_instance" "rds" {
  allocated_storage                     = 20
  auto_minor_version_upgrade            = true
  apply_immediately                     = true
  backup_retention_period               = 5
  db_subnet_group_name                  = aws_db_subnet_group.rds.id
  delete_automated_backups              = true
  deletion_protection                   = true
  enabled_cloudwatch_logs_exports       = ["agent", "error"]
  engine                                = "sqlserver-se"
  engine_version                        = "15.00.4198.2.v1"
  identifier                            = "rds"
  instance_class                        = "db.t3.xlarge"
  kms_key_id                            = data.aws_kms_key.by_id.arn
  license_model                         = "license-included"
  manage_master_user_password           = true
  monitoring_interval                   = 5
  monitoring_role_arn                   = aws_iam_role.rds_role.arn
  multi_az                              = true
  performance_insights_enabled          = true
  performance_insights_kms_key_id       = data.aws_kms_key.by_id.arn
  performance_insights_retention_period = 7
  port                                  = "1433"
  publicly_accessible                   = false
  skip_final_snapshot                   = true
  storage_encrypted                     = true
  storage_type                          = "gp3"
  vpc_security_group_ids                = [aws_security_group.sg.id]
  username                              = "admin"
  timeouts {
    create = "3h"
    delete = "3h"
    update = "3h"
  }
}

# Add an AWS CloudWatch Alarm to monitor the CPU utilization of the RDS instance
resource "aws_cloudwatch_metric_alarm" "rds_cpu_utilization" {
  alarm_name          = "rds-cpu-utilization-alarm"
  comparison_operator = "GreaterThanOrEqualToThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/RDS"
  period              = "300"
  statistic           = "Average"
  threshold           = "70"
  alarm_actions       = [aws_sns_topic.rds_alarms.arn]
  dimensions = {
    DBInstanceIdentifier = aws_db_instance.rds.identifier
  }
}

# Create an SNS topic for RDS alarms
resource "aws_sns_topic" "rds_alarms" {
  name = "rds-alarms"
}

# Subscribe to the SNS topic via email
resource "aws_sns_topic_subscription" "rds_alarms_email" {
  topic_arn = aws_sns_topic.rds_alarms.arn
  protocol  = "email"
  endpoint  = "admin@example.com"
}

