expected:
# Create public AWS ECR Repository via the 'awscc' provider

resource "awscc_ecr_public_repository" "example" {
  repository_name = "example"
  tags = [{
    key   = "Managed By"
    value = "AWSCC"
  }]
}

# Add a new AWS S3 bucket to store logs
resource "awscc_s3_bucket" "logs_bucket" {
  bucket_name = "example-logs-bucket"
  tags = [{
    key   = "Managed By"
    value = "AWSCC"
  }]

  # Enable server-side encryption
  bucket_encryption {
    server_side_encryption_configuration {
      rule {
        apply_server_side_encryption_by_default {
          sse_algorithm = "AES256"
        }
      }
    }
  }

  # Enable logging
  logging_configuration {
    destination_bucket_name = "example-logs-bucket"
    role_arn                 = aws_iam_role.logs_bucket_role.arn
  }
}

# Create an IAM role that allows the S3 bucket to write logs
resource "aws_iam_role" "logs_bucket_role" {
  name = "logs_bucket_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{
      Action = "sts:AssumeRole",
      Effect = "Allow",
      Principal = {
        Service = "s3.amazonaws.com"
      }
    }]
  })
}

# Attach a policy to the IAM role that allows it to write logs to the bucket
resource "aws_iam_role_policy" "logs_bucket_policy" {
  name = "logs_bucket_policy"
  role = aws_iam_role.logs_bucket_role.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [{
      Action = [
        "s3:PutObject",
        "s3:GetBucketLogging"
      ],
      Effect = "Allow",
      Resource = [
        awscc_s3_bucket.logs_bucket.arn,
        "${awscc_s3_bucket.logs_bucket.arn}/*"
      ]
    }]
  })
}

