data "aws_iam_policy_document" "elasticsearch-log-publishing-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "logs:PutLogEventsBatch",
    ]

    resources = ["arn:aws:logs:*"]

    principals {
      identifiers = ["es.amazonaws.com"] // change this to service endpoint for desired resource (e.g. s3.amazonaws.com)
      type        = "Service"
    }
  }
}

# Create CloudWatch Logs resource policy
resource "awscc_logs_resource_policy" "this" {
  policy_document = data.aws_iam_policy_document.elasticsearch-log-publishing-policy.json
  policy_name     = "elasticsearch-log-publishing-policy"
}

expected:
# Create CloudWatch Logs resource policy for elasticsearch via the 'awscc' provider

# Create IAM Policy Document
data "aws_iam_policy_document" "elasticsearch-log-publishing-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "logs:PutLogEventsBatch",
    ]

    resources = ["arn:aws:logs:*"]

    principals {
      identifiers = ["es.amazonaws.com"] // change this to service endpoint for desired resource (e.g. s3.amazonaws.com)
      type        = "Service"
    }
  }
}

# Create CloudWatch Logs resource policy
resource "awscc_logs_resource_policy" "this" {
  policy_document = data.aws_iam_policy_document.elasticsearch-log-publishing-policy.json
  policy_name     = "elasticsearch-log-publishing-policy"
}

# Add an S3 bucket to store the CloudWatch logs
resource "aws_s3_bucket" "cloudwatch_logs_bucket" {
  bucket = "cloudwatch-logs-bucket-for-elasticsearch"
  acl    = "private"

  versioning {
    enabled = true
  }

  logging {
    target_bucket = "log-archive-bucket"
    target_prefix = "CloudWatchLogs/"
  }

  tags = {
    Name        = "CloudWatchLogsBucketForElasticsearch"
    Environment = "Production"
  }
}

# Add a lifecycle rule to transition logs to infrequent access after 30 days
resource "aws_s3_bucket_lifecycle_configuration" "cloudwatch_logs_bucket_lifecycle" {
  bucket = aws_s3_bucket.cloudwatch_logs_bucket.id

  rule {
    id      = "TransitionToIA"
    enabled = true

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    expiration {
      days = 90
    }

    filter {
      prefix = "CloudWatchLogs/"
    }
  }
}

